1	type Cell = [number, number]; // [x, y]
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1, 0], [1, 0],
6	  [-1, 1], [0, 1], [1, 1],
7	];
8	const BIRTH_NEIGHBORS = 3;
9	const SURVIVAL_NEIGHBORS = 2;
10	
11	function key(x: number, y: number): string {
12	  return `${x},${y}`;
13	}
14	
15	function parseKey(cellKey: string): Cell {
16	  const [x, y] = cellKey.split(",").map(Number);
17	  return [x, y];
18	}
19	
20	function countLiveNeighbors(cells: Cell[]): Map<string, number> {
21	  const counts = new Map<string, number>();
22	  for (const [x, y] of cells) {
23	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
24	      const neighbor = key(x + dx, y + dy);
25	      counts.set(neighbor, (counts.get(neighbor) ?? 0) + 1);
26	    }
27	  }
28	  return counts;
29	}
30	
31	function isAliveNextGeneration(
32	  liveNeighbors: number,
33	  isCurrentlyAlive: boolean,
34	): boolean {
35	  const isBorn = liveNeighbors === BIRTH_NEIGHBORS;
36	  const survives = liveNeighbors === SURVIVAL_NEIGHBORS && isCurrentlyAlive;
37	  return isBorn || survives;
38	}
39	
40	export function nextGeneration(cells: Cell[]): Cell[] {
41	  const living = new Set(cells.map(([x, y]) => key(x, y)));
42	  const neighborCounts = countLiveNeighbors(cells);
43	
44	  const next: Cell[] = [];
45	  for (const [cellKey, count] of neighborCounts) {
46	    if (isAliveNextGeneration(count, living.has(cellKey))) {
47	      next.push(parseKey(cellKey));
48	    }
49	  }
50	  return next;
51	}
