1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("returns an empty array when given no living cells — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("a single living cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("a pair of living cells both die from underpopulation — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("a dead cell with exactly 3 live neighbors becomes alive (reproduction) — (1,1) joins output", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
16	    expect(result).toContainEqual([1, 1]);
17	  });
18	  it("a live cell with 2 live neighbors survives (survival)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
20	    expect(result).toContainEqual([1, 0]);
21	  });
22	  it("a live cell with more than 3 live neighbors dies (overpopulation) — center (1,1) dies", () => {
23	    const result = nextGeneration([
24	      [0, 0], [1, 0], [2, 0],
25	      [1, 1],
26	      [0, 2], [1, 2], [2, 2],
27	    ]);
28	    expect(result).not.toContainEqual([1, 1]);
29	  });
30	  it("a block is a still life and stays unchanged — [(0,0),(1,0),(0,1),(1,1)] unchanged", () => {
31	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
32	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
33	      new Set(["0,0", "1,0", "0,1", "1,1"]),
34	    );
35	  });
36	  it("a blinker oscillates — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
37	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
38	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
39	      new Set(["-1,1", "0,1", "1,1"]),
40	    );
41	  });
42	  it.todo("handles negative coordinates correctly");
43	});
